module multi_pipe_4bit #(
    parameter size = 4,
    parameter N = 2 * size
) (
    input 						clk,
    input 						rst_n,
    input	[size-1:0]			mul_a,
    input	[size-1:0]			mul_b,
    output	reg	[size*2-1:0]	mul_out
);

    wire [7:0] mul_a_ext;
    wire [7:0] mul_b_ext;
    assign mul_a_ext = {4'b0000, mul_a};
    assign mul_b_ext = {4'b0000, mul_b};

    wire [7:0] partial_products [3:0];
    genvar i;
    generate
        for(i = 0; i < 4; i = i + 1) begin : gen_partial_products
            assign partial_products[i] = (mul_b_ext[i]) ? (mul_a_ext << i) : 'd0;
        end
    endgenerate

    reg [7:0] sum_tmp1, sum_tmp2;
    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            sum_tmp1 <= 0;
            sum_tmp2 <= 0;
        end else begin
            sum_tmp1 <= (mul_b_ext[0] ? mul_a_ext : 0) + (mul_b_ext[1] ? mul_a_ext << 1 : 0);
            sum_tmp2 <= (mul_b_ext[2] ? mul_a_ext << 2 : 0) + (mul_b_ext[3] ? mul_a_ext << 3 : 0);
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if(!rst_n) begin
            mul_out <= 0;
        end else begin
            mul_out <= sum_tmp1 + sum_tmp2;
        end
    end

endmodule
